import { useState, useEffect, useCallback } from "react";

const SLIDE_IMAGES = [
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  "",
  "",
];

const SLIDE_TITLES = [
  "Title Slide",
  "01 // Introduction: What Is the Metaverse Workplace?",
  "02 // The Core Problem: Technology Outpacing Law",
  "03 // Labor Issues: Precarity in the Virtual Realm",
  "04 // Data Extraction: The New Frontier of Monitoring",
  "05 // Privacy Concerns: Surveillance and Ownership",
  "06 // Case Study: Meta and the Reality of Virtual Work",
  "07 // Societal Impact: Reshaping the Future of Work",
  "08 // Major Challenges in Researching the Metaverse",
  "09 // Conclusion: The Need for Governance",
  "10 // References and Resources",
  "Thank You",
];

const DOC_SECTIONS = [
  {
    heading: "Topic Identification",
    isRefs: false,
    content: [
      "This project examines the unprecedented level of employee monitoring, biometric data tracking, and privacy risks that emerge inside virtual corporate environments. The research covers three main areas: labor issues (including gig work precarity, content moderation, and challenges to unionization), data extraction (the use of biometric and behavioral data to monitor employee performance and engagement), and privacy concerns (surveillance, data ownership, and potential misuse of personal information on virtual work platforms).",
      "The central problem is straightforward: the metaverse workspace is being built faster than the laws, labor rights, and privacy protections that are supposed to govern it. This project investigates what is actually happening inside virtual workspaces and what the ethical implications, risks, and governance responsibilities are as a result. By analyzing real-world examples like Meta and its ongoing privacy policy debates, the goal is to show where the gaps are and why they matter.",
    ],
  },
  {
    heading: "Why This Topic Matters",
    isRefs: false,
    content: [
      "The metaverse workplace is a virtual reality and digital environment that changes how people work, communicate, and collaborate. While technology can offer flexibility and new opportunities, it also creates serious ethical concerns that are easy to overlook until they affect real people.",
      "Workers in virtual environments could face exploitation, unstable employment, and difficulty getting fair treatment. At the same time, VR systems collect large amounts of biometric and personal data, allowing employers to closely monitor behavior, attention levels, and even emotions. That raises major questions about privacy and surveillance, especially since current labor laws and privacy laws were not designed with a virtual environment in mind.",
      "This topic matters because the metaverse has the potential to reshape the future of work entirely, and if it is not regulated properly, it could seriously threaten worker rights, personal privacy, and individual freedom.",
    ],
  },
  {
    heading: "Mode of Delivery",
    isRefs: false,
    content: [
      "This information is presented as a website built with HTML, CSS, and React. The site covers how virtual reality and metaverse technology is entering the workplace and introducing new ethical challenges. It explores how the VR workplace affects workers, society, and the future of employment, and it is designed to be embedded into a Google Site using a full-page embed.",
    ],
  },
  {
    heading: "Project Components",
    isRefs: false,
    content: [
      "Section one provides a clear overview of the metaverse workplace, what immersive platforms are, and how modern companies use them for meetings, training, and collaboration.",
      "Section two covers labor-related and ethical issues including worker exploitation, job precarity, outsourced content moderation, and the specific challenges of unionization in a metaverse setting.",
      "Section three examines how metaverse technology collects biometric and behavioral data, and how that technology enables entirely new forms of employee surveillance.",
      "Section four is a focused discussion of privacy issues related to consent, data storage, and the potential misuse of personal and biometric data in virtual corporate environments, including how existing privacy and labor laws fall short.",
      "Section five looks at the broader societal impact: how the metaverse may affect privacy norms, worker rights, inequality, and what the future of work could look like if these issues are not addressed.",
    ],
  },
  {
    heading: "Major Challenges",
    isRefs: false,
    content: [
      "The biggest challenge in researching this topic is that the metaverse is constantly changing. Policies, technology, and corporate practices can shift quickly, which makes it hard to rely on long-term data or consistent regulations. What is accurate today might be outdated after the next software update.",
      "There is also a clear lack of legal framework addressing labor rights and biometric privacy in virtual work environments. That creates gray areas when trying to analyze accountability and corporate responsibility.",
      "Additionally, much of the labor involved in running metaverse platforms is outsourced or hidden from public view, making it harder to access firsthand accounts of working conditions. Finally, presenting complex technical and ethical issues like biometric surveillance and data extraction in a way that is understandable to a general audience is a real challenge in itself.",
    ],
  },
  {
    heading: "References",
    isRefs: true,
    content: [
      "Anthony, Tristan. (2026). Meta is closing its VR workplace app amid Reality Labs layoffs. January 16, 2026.",
      "Berrick, Daniel & Spivack, Jameson. (2023). Unpacking the Privacy Implications of Extended Reality. Future of Privacy Forum.",
      "Jang, Eric. (2022). Ready Employee One: Data Privacy Within the Metaverse. June 24, 2022.",
      "Ray, Jody. (2024). Kenyan Courts Keep Telling Meta to Let Workers Unionize. February 14, 2024.",
    ],
  },
];

const css = `
  @import url('https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Barlow:ital,wght@0,300;0,400;0,600;0,700;1,300&family=Barlow+Condensed:wght@400;600;700;800&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg: #05080e;
    --surface: #080d18;
    --surface2: #0c1220;
    --border: rgba(0,255,180,0.12);
    --border2: rgba(0,255,180,0.25);
    --green: #00ffb4;
    --amber: #ffb400;
    --red: #ff3b5c;
    --text: #d4e0f0;
    --muted: #4a6080;
    --mono: 'Share Tech Mono', monospace;
    --body: 'Barlow', sans-serif;
    --head: 'Barlow Condensed', sans-serif;
  }

  body { background: var(--bg); color: var(--text); font-family: var(--body); overflow-x: hidden; }

  body::after {
    content: '';
    position: fixed; inset: 0;
    background: repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,255,180,0.012) 2px, rgba(0,255,180,0.012) 4px);
    pointer-events: none; z-index: 9999;
  }
  body::before {
    content: '';
    position: fixed; inset: 0;
    background-image: linear-gradient(rgba(0,255,180,0.03) 1px, transparent 1px), linear-gradient(90deg, rgba(0,255,180,0.03) 1px, transparent 1px);
    background-size: 40px 40px;
    pointer-events: none; z-index: 0;
  }

  /* HEADER */
  .site-header {
    position: relative; z-index: 20;
    border-bottom: 1px solid var(--border);
    padding: 14px 28px;
    display: flex; align-items: center; justify-content: space-between;
    background: rgba(5,8,14,0.92); backdrop-filter: blur(10px);
    flex-wrap: wrap; gap: 10px;
  }
  .hdr-logo { font-family: var(--mono); font-size: 11px; color: var(--green); letter-spacing: 0.15em; opacity: 0.7; }
  .hdr-center { text-align: center; flex: 1; min-width: 200px; }
  .hdr-center h1 { font-family: var(--head); font-size: clamp(13px,2vw,18px); font-weight: 700; letter-spacing: 0.1em; text-transform: uppercase; color: var(--text); line-height: 1.2; }
  .hdr-center .sub { font-family: var(--mono); font-size: 9px; color: var(--muted); margin-top: 3px; letter-spacing: 0.08em; }
  .hdr-right { font-family: var(--mono); font-size: 10px; color: var(--muted); text-align: right; line-height: 1.7; }
  .live-dot { display: inline-block; width: 6px; height: 6px; background: var(--green); border-radius: 50%; margin-right: 5px; box-shadow: 0 0 6px var(--green); animation: blink 1.2s infinite; vertical-align: middle; }
  @keyframes blink { 0%,100%{opacity:1} 50%{opacity:0.3} }

  /* TABS */
  .tab-bar { position: relative; z-index: 10; display: flex; background: var(--surface); border-bottom: 1px solid var(--border); }
  .tab-btn { font-family: var(--mono); font-size: 11px; letter-spacing: 0.12em; text-transform: uppercase; padding: 13px 28px; border: none; background: transparent; color: var(--muted); cursor: pointer; border-bottom: 2px solid transparent; transition: all 0.2s; }
  .tab-btn:hover { color: var(--text); }
  .tab-btn.active { color: var(--green); border-bottom-color: var(--green); background: rgba(0,255,180,0.03); }

  /* VIEWS */
  .view { display: none; position: relative; z-index: 5; }
  .view.visible { display: block; animation: fadeUp 0.3s ease; }
  @keyframes fadeUp { from{opacity:0;transform:translateY(8px)} to{opacity:1;transform:translateY(0)} }

  /* SLIDESHOW */
  #slideshow-view { padding: 28px 20px 60px; }
  .slide-stage { max-width: 960px; margin: 0 auto; }

  .slide-card {
    background: #000;
    border: 1px solid var(--border);
    border-radius: 4px;
    overflow: hidden;
    position: relative;
    box-shadow: 0 0 40px rgba(0,255,180,0.04);
  }
  .slide-card::before {
    content: '';
    position: absolute; top: 0; left: 0; right: 0; height: 2px;
    background: linear-gradient(90deg, transparent, var(--green), transparent);
    opacity: 0.5; z-index: 1;
  }

  .slide-img-wrap { position: relative; width: 100%; padding-top: 56.25%; background: #000; }
  .slide-img-wrap img { position: absolute; inset: 0; width: 100%; height: 100%; object-fit: contain; display: block; }
  .slide-img-wrap img.entering { animation: fadeUp 0.25s ease; }

  .slide-info-bar {
    display: flex; justify-content: space-between; align-items: center;
    padding: 9px 18px;
    border-top: 1px solid var(--border);
    background: rgba(0,0,0,0.5);
  }
  .slide-info-bar .slide-name { font-family: var(--mono); font-size: 9px; color: var(--muted); letter-spacing: 0.08em; }
  .slide-info-bar .slide-num-badge { font-family: var(--mono); font-size: 9px; color: var(--green); letter-spacing: 0.1em; }

  /* Thumbnail strip */
  .thumb-strip {
    max-width: 960px; margin: 12px auto 0;
    display: flex; gap: 6px; overflow-x: auto; padding-bottom: 6px;
    scrollbar-width: thin; scrollbar-color: rgba(0,255,180,0.15) transparent;
  }
  .thumb {
    flex-shrink: 0; width: 78px; border-radius: 3px; overflow: hidden;
    border: 1px solid var(--border); cursor: pointer; transition: all 0.18s; opacity: 0.45;
  }
  .thumb:hover { opacity: 0.75; border-color: rgba(0,255,180,0.3); }
  .thumb.active { border-color: var(--green); box-shadow: 0 0 10px rgba(0,255,180,0.25); opacity: 1; }
  .thumb img { width: 100%; display: block; }

  /* Controls */
  .slide-controls {
    display: flex; align-items: center; justify-content: space-between;
    max-width: 960px; margin: 14px auto 0; padding: 0 2px;
  }
  .ctrl-btn { font-family: var(--mono); font-size: 11px; letter-spacing: 0.1em; padding: 9px 20px; border-radius: 2px; background: var(--surface); border: 1px solid var(--border); color: var(--text); cursor: pointer; transition: all 0.2s; }
  .ctrl-btn:hover:not(:disabled) { background: var(--surface2); border-color: var(--green); color: var(--green); }
  .ctrl-btn:disabled { opacity: 0.22; cursor: default; }
  .dots-row { display: flex; flex-direction: column; align-items: center; gap: 8px; }
  .dots { display: flex; gap: 5px; align-items: center; }
  .dot-btn { width: 5px; height: 5px; border-radius: 50%; background: #1a2535; border: 1px solid var(--border); cursor: pointer; transition: all 0.2s; padding: 0; }
  .dot-btn.active { background: var(--green); box-shadow: 0 0 6px var(--green); width: 16px; border-radius: 2px; }
  .slide-count { font-family: var(--mono); font-size: 10px; color: var(--muted); letter-spacing: 0.1em; }

  /* DOCUMENT */
  #doc-view { max-width: 740px; margin: 44px auto 80px; padding: 0 24px; }
  .doc-header { padding-bottom: 32px; border-bottom: 1px solid var(--border); margin-bottom: 40px; }
  .doc-eyebrow { font-family: var(--mono); font-size: 10px; color: var(--green); letter-spacing: 0.15em; margin-bottom: 14px; }
  .doc-header h2 { font-family: var(--head); font-size: clamp(20px,4vw,34px); font-weight: 800; letter-spacing: 0.04em; text-transform: uppercase; color: #fff; line-height: 1.15; margin-bottom: 16px; }
  .doc-byline { font-family: var(--mono); font-size: 10px; color: var(--muted); line-height: 2; letter-spacing: 0.1em; }
  .doc-section { margin-bottom: 36px; }
  .doc-section h3 { font-family: var(--head); font-size: 14px; font-weight: 700; letter-spacing: 0.15em; text-transform: uppercase; color: var(--green); margin-bottom: 16px; display: flex; align-items: center; gap: 10px; }
  .doc-section h3::after { content: ''; flex: 1; height: 1px; background: var(--border); }
  .doc-section p { font-size: 15px; line-height: 1.82; color: rgba(212,224,240,0.78); margin-bottom: 14px; }
  .doc-section ol { padding-left: 20px; }
  .doc-section ol li { font-size: 14px; color: rgba(212,224,240,0.7); line-height: 1.75; margin-bottom: 8px; }

  @media (max-width: 600px) {
    .site-header { padding: 12px 14px; }
    #slideshow-view { padding: 14px 10px 40px; }
    .thumb { width: 54px; }
    .ctrl-btn { padding: 8px 14px; font-size: 10px; }
  }
`;

export default function App() {
  const [view, setView] = useState("slideshow");
  const [current, setCurrent] = useState(0);
  const [entering, setEntering] = useState(false);
  const total = SLIDE_IMAGES.length;

  const goTo = useCallback((idx) => {
    if (idx < 0 || idx >= total || idx === current) return;
    setEntering(true);
    setCurrent(idx);
    setTimeout(() => setEntering(false), 300);
  }, [total, current]);

  useEffect(() => {
    const handler = (e) => {
      if (view !== "slideshow") return;
      if (e.key === "ArrowRight" || e.key === "ArrowDown") goTo(current + 1);
      if (e.key === "ArrowLeft" || e.key === "ArrowUp") goTo(current - 1);
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [view, current, goTo]);

  // Auto-scroll thumbnail strip to keep active thumb visible
  useEffect(() => {
    const strip = document.querySelector(".thumb-strip");
    const active = strip && strip.querySelectorAll(".thumb")[current];
    if (active) active.scrollIntoView({ behavior: "smooth", block: "nearest", inline: "center" });
  }, [current]);

  return (
    <>
      <style>{css}</style>

      <header className="site-header">
        <div className="hdr-logo">[ SYS_ACTIVE ]</div>
        <div className="hdr-center">
          <h1>Ethics of the Metaverse Workplace</h1>
          <div className="sub">Luis Couttolenc &middot; University of Hartford &middot; April 27, 2026</div>
        </div>
        <div className="hdr-right">
          <div><span className="live-dot" />SESSION: 2026-04-27</div>
          <div>UIST: Technology and Society</div>
        </div>
      </header>

      <div className="tab-bar">
        <button className={`tab-btn ${view === "slideshow" ? "active" : ""}`} onClick={() => setView("slideshow")}>
          Slideshow View
        </button>
        <button className={`tab-btn ${view === "doc" ? "active" : ""}`} onClick={() => setView("doc")}>
          Document View
        </button>
      </div>

      {/* ---- SLIDESHOW ---- */}
      <div id="slideshow-view" className={`view ${view === "slideshow" ? "visible" : ""}`}>
        <div className="slide-stage">

          <div className="slide-card">
            <div className="slide-img-wrap">
              <img
                key={current}
                src={`data:image/png;base64,${SLIDE_IMAGES[current]}`}
                alt={SLIDE_TITLES[current]}
                className={entering ? "entering" : ""}
              />
            </div>
            <div className="slide-info-bar">
              <span className="slide-name">{SLIDE_TITLES[current]}</span>
              <span className="slide-num-badge">{current + 1} / {total}</span>
            </div>
          </div>

          <div className="thumb-strip">
            {SLIDE_IMAGES.map((img, i) => (
              <div key={i} className={`thumb ${i === current ? "active" : ""}`} onClick={() => goTo(i)} title={SLIDE_TITLES[i]}>
                <img src={`data:image/png;base64,${img}`} alt={`Slide ${i + 1}`} />
              </div>
            ))}
          </div>
        </div>

        <div className="slide-controls">
          <button className="ctrl-btn" onClick={() => goTo(current - 1)} disabled={current === 0}>
            &larr; PREV
          </button>
          <div className="dots-row">
            <div className="dots">
              {SLIDE_IMAGES.map((_, i) => (
                <button key={i} className={`dot-btn ${i === current ? "active" : ""}`} onClick={() => goTo(i)} />
              ))}
            </div>
            <div className="slide-count">{current + 1} / {total}</div>
          </div>
          <button className="ctrl-btn" onClick={() => goTo(current + 1)} disabled={current === total - 1}>
            NEXT &rarr;
          </button>
        </div>
      </div>

      {/* ---- DOCUMENT ---- */}
      <div id="doc-view" className={`view ${view === "doc" ? "visible" : ""}`}>
        <div className="doc-header">
          <div className="doc-eyebrow">MINI PROJECT PROPOSAL // UIST: TECHNOLOGY AND SOCIETY</div>
          <h2>The Ethics of the Metaverse Workplace:<br />Examining Labor Issues, Data Extraction, and Privacy in Virtual Corporate Environments</h2>
          <div className="doc-byline">
            AUTHOR: Luis Couttolenc<br />
            INSTITUTION: University of Hartford<br />
            COURSE: UIST: Technology and Society &middot; Dr. Rainwater<br />
            DATE: February 3, 2026
          </div>
        </div>

        {DOC_SECTIONS.map((sec, i) => (
          <div className="doc-section" key={i}>
            <h3>{sec.heading}</h3>
            {sec.isRefs ? (
              <ol>{sec.content.map((r, j) => <li key={j}>{r}</li>)}</ol>
            ) : (
              sec.content.map((p, j) => <p key={j}>{p}</p>)
            )}
          </div>
        ))}
      </div>
    </>
  );
}
